mapper.select:
SELECT MAX(n.notice_id) AS noticeId, n.group_id AS groupId, n.title, n.content, n.notice_type AS noticeType, n.sender_id AS senderId, s.real_name AS senderName, n.biz_type AS bizType, n.biz_id AS bizId, MAX(n.create_time) AS createTime, COUNT(n.notice_id) AS receiverCount, SUM(IFNULL(n.is_read, 0)) AS readCount, GROUP_CONCAT(r.real_name ORDER BY n.receiver_id SEPARATOR ',') AS receiverNames FROM sys_notification n LEFT JOIN sys_user s ON n.sender_id = s.user_id AND s.is_deleted = 0 LEFT JOIN sys_user r ON n.receiver_id = r.user_id AND r.is_deleted = 0
AND n.title LIKE CONCAT('%', #{keyword}, '%')
GROUP BY n.group_id, n.title, n.content, n.notice_type, n.sender_id, s.real_name, n.biz_type, n.biz_id ORDER BY MAX(n.notice_id) DESC LIMIT #{offset}, #{limit}
